import requests

BASE_URL = "http://localhost:8080"

def test_create_procedure_missing_encounter_returns_422(clinician_token):
    payload = {
        "resourceType": "Procedure",
        "status": "completed",
        "subject": {"reference": "Patient/test-patient-1"},
        "encounter": {"reference": "Encounter/nonexistent-enc-999"},
        "code": {
            "coding": [{"system": "http://snomed.info/sct", "code": "71388002"}]
        }
    }
    headers = {"Authorization": f"Bearer {clinician_token}",
               "Content-Type": "application/fhir+json"}
    resp = requests.post(f"{BASE_URL}/Procedure", json=payload, headers=headers)
    assert resp.status_code == 422
    body = resp.json()
    assert body.get("resourceType") == "OperationOutcome"
    issues = body.get("issue", [])
    assert any("encounter" in str(i).lower() for i in issues)

import requests
import pytest

BASE_URL = "http://localhost:8080"
MIN_PATIENT_ID = "1"
ACCEPTED_CODES = {201, 422}

def test_create_procedure_subject_reference_at_minimum_length(
        clinician_token, open_encounter_id):
    payload = {
        "resourceType": "Procedure",
        "status": "completed",
        "subject": {"reference": f"Patient/{MIN_PATIENT_ID}"},
        "encounter": {"reference": f"Encounter/{open_encounter_id}"},
        "code": {
            "coding": [{"system": "http://snomed.info/sct", "code": "71388002"}]
        }
    }
    headers = {"Authorization": f"Bearer {clinician_token}",
               "Content-Type": "application/fhir+json"}
    resp = requests.post(f"{BASE_URL}/Procedure", json=payload, headers=headers)
    assert resp.status_code in ACCEPTED_CODES, (
        f"Unexpected status {resp.status_code} for min-length subject id")
    body = resp.json()
    if resp.status_code == 201:
        assert body["resourceType"] == "Procedure"
    else:
        assert body.get("resourceType") == "OperationOutcome"

import requests

BASE_URL = "http://localhost:8080"

def test_create_procedure_unauthorized_user_denied(
        non_clinician_token, open_encounter_id):
    payload = {
        "resourceType": "Procedure",
        "status": "completed",
        "subject": {"reference": "Patient/test-patient-1"},
        "encounter": {"reference": f"Encounter/{open_encounter_id}"},
        "code": {
            "coding": [{"system": "http://snomed.info/sct", "code": "71388002"}]
        }
    }
    headers = {"Authorization": f"Bearer {non_clinician_token}",
               "Content-Type": "application/fhir+json"}
    resp = requests.post(f"{BASE_URL}/Procedure", json=payload, headers=headers)
    assert resp.status_code in (401, 403), (
        f"Expected 401 or 403 for unpermitted user, got {resp.status_code}")
